input.steps:
- {title: "Load 10x triplet and create Seurat object", description: "ReadMtx the matrix/barcodes/features, CreateSeuratObject with min.cells=3, min.features=200"}
- {title: "QC and filtering", description: "Calculate percent.mt (mouse MT genes), subset to nFeature_RNA 200–8000 and percent.mt ≤ 10"}
- {title: "Normalization and feature selection", description: "NormalizeData, FindVariableFeatures, ScaleData"}
- {title: "PCA and neighborhood graph", description: "RunPCA (default 50), inspect ElbowPlot, then FindNeighbors and downstream steps using selected dims"}
- {title: "Clustering and UMAP", description: "FindClusters (resolution=0.8), RunUMAP on PCA reduction"}
- {title: "Find markers and summarize", description: "FindAllMarkers (min.pct=0.25), display UMAP and top 5 markers per cluster"}
